using System.Net;
using System.Text;
using PicoDI.Abs;
using PicoNode.Web;
using PicoWeb;

// DI First WebAPI with inline MapXX endpoints and controller routing
//
// AOT-safe DI registration using RegisterScoped<T>() — PicoDI.Gen generates
// compile-time registrations. Works with `dotnet publish -p:PublishAot=true`.

var container = new TestContainer();
var app = new WebApp(container);

// Controller endpoints (auto-generated by Controllers.Gen):
// UsersController.GetUser(int id) => GET /api/users/user/{id}
EndpointRegistrar.RegisterAll(app);

// Inline endpoint — exact match
app.MapGet("/api/health", (WebContext ctx, CancellationToken _) =>
    ValueTask.FromResult(WebResults.Json(200, """{"status":"ok"}""", "OK")));

var server = new WebServer(
    app,
    new WebServerOptions { Endpoint = new IPEndPoint(IPAddress.Loopback, 7004) }
);
await server.StartAsync();
Console.WriteLine($"Listening on {server.LocalEndPoint}");
await Task.Delay(Timeout.Infinite);
await server.DisposeAsync();

// AOT-safe ISvcContainer — no PicoDI.Gen required
sealed class TestContainer : ISvcContainer
{
    public ISvcContainer Register(SvcDescriptor descriptor) => this;
    public bool IsRegistered(Type serviceType) => false;
    public ISvcScope CreateScope() => new TestScope();
    public ValueTask DisposeAsync() => ValueTask.CompletedTask;
}

sealed class TestScope : ISvcScope
{
    public object GetService(Type serviceType) => null!;
    public IReadOnlyList<object> GetServices(Type serviceType) => Array.Empty<object>();
    public bool TryGetService(Type serviceType, out object? result) { result = null; return false; }
    public bool TryGetServices(Type serviceType, out IReadOnlyList<object>? result) { result = null; return false; }
    public ISvcScope CreateScope() => this;
    public ValueTask DisposeAsync() => ValueTask.CompletedTask;
}
